$py_main_py = @"
import zlib,base64,pathlib
p=pathlib.Path(r'C:\kangsub_bot\main.py')
p.parent.mkdir(parents=True,exist_ok=True)
raw=base64.b64decode("".join([l.strip() for l in open(r'$env:TEMP\d_main_py.b64').readlines()]))
p.write_bytes(zlib.decompress(raw))
print(f'main.py → {p} ({p.stat().st_size:,} bytes)')
import ast
ext=str(p).split(".")[-1]
if ext=="py":
    try:
        ast.parse(p.read_text(encoding="utf-8"))
        print("  Syntax OK")
    except SyntaxError as e:
        print(f"  Syntax ERROR: {e}")
"@
[IO.File]::WriteAllText("$env:TEMP\d_main_py.b64", $b_main_py)
$py_main_py | Out-File -Encoding utf8 "$env:TEMP\wr_main_py.py"
py "$env:TEMP\wr_main_py.py"

